using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    #region CreateOrder

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10.00m, 2), ("Gadget", 25.00m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(45.00m, order.Total);
        Assert.AreEqual(2, order.Items.Count);
        Assert.IsNotNull(order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_CalculatesTotalCorrectly()
    {
        // Arrange
        var items = CreateItems(("Book", 15.99m, 3));

        // Act
        var order = _service.CreateOrder("cust-2", items);

        // Assert
        Assert.AreEqual(47.97m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Item", 5.00m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));
        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentTime()
    {
        // Arrange
        var before = DateTime.UtcNow;
        var items = CreateItems(("Clock", 20.00m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt} should be between {before} and {after}");
    }

    [TestMethod]
    public void CreateOrder_GeneratesUniqueIds()
    {
        // Arrange
        var items = CreateItems(("Item", 1.00m, 1));

        // Act
        var order1 = _service.CreateOrder("cust-1", items);
        var order2 = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsOrder()
    {
        // Arrange
        var items = CreateItems(("Pen", 2.50m, 4));
        var created = _service.CreateOrder("cust-1", items);

        // Act
        var retrieved = _service.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
        Assert.AreEqual("cust-1", retrieved.CustomerId);
    }

    [TestMethod]
    public void GetOrder_WithNonExistingId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_WithOrders_ReturnsAllMatching()
    {
        // Arrange
        var items = CreateItems(("A", 1.00m, 1));
        _service.CreateOrder("cust-A", items);
        _service.CreateOrder("cust-A", items);
        _service.CreateOrder("cust-B", items);

        // Act
        var orders = _service.GetOrdersByCustomer("cust-A");

        // Assert
        Assert.AreEqual(2, orders.Count);
        Assert.IsTrue(orders.All(o => o.CustomerId == "cust-A"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithNoOrders_ReturnsEmptyList()
    {
        var orders = _service.GetOrdersByCustomer("unknown-customer");

        Assert.AreEqual(0, orders.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_DoesNotReturnOtherCustomerOrders()
    {
        // Arrange
        var items = CreateItems(("X", 5.00m, 1));
        _service.CreateOrder("cust-X", items);

        // Act
        var orders = _service.GetOrdersByCustomer("cust-Y");

        // Assert
        Assert.AreEqual(0, orders.Count);
    }

    #endregion
}

